import React from 'react'
import { useNavigate } from 'react-router-dom';
import Loader from '../../Loader'


const TablaDatosAnalisisOp = ({ oper }) => {

    const navigate = useNavigate()
    const arrOrdenar = []

    const backToInfo = () => navigate('/reports')

    if (oper) { arrOrdenar.push(oper.sort((a, b) => a['ddd_results_date_created'] < b['ddd_results_date_created'])) }
    return (
        <>
            {arrOrdenar[0].length > 0 ?
                <section className='tablaDatos'>
                    <div align='center'>
                        <button onClick={() => backToInfo()} key={`buttonbacktoinfo`} >Back to Reports</button><br />
                        {/* <button onClick={() => exportToCSV(arrOrdenado, ' *INFORME* ')} key={`buttongetexcel`} >Exportar a Excel</button><br /> */}
                    </div>
                    <table id='tabla' key={`tablekeymain`}>
                        <thead key={`keytehead`}>
                            <tr className='tr-table'><th colSpan="100%"><h6 className=''>--</h6></th></tr>
                            <tr className='tr-table' key={`keyheader`}>
                                <th className='th-table' key={`keyth1`}><h6 className=''>N`</h6></th >
                                <th className='th-table' key={`keyth5`}><h6 className=''>date_created</h6></th>
                                <th className='th-table' key={`keyth6`}><h6 className=''>type</h6></th>
                                <th className='th-table' key={`keyth7`}><h6 className=''>detail_avail_quant</h6></th>
                                <th className='th-table' key={`keyth8`}><h6 className=''>total</h6></th>
                                <th className='th-table' key={`keyth10`}><h6 className=''>ref_value</h6></th>
                            </tr >
                        </thead >
                        <tbody key={`keybody_`} id={`keybody`}>
                            {arrOrdenar[0].map((valor, index) => {
                                return (
                                    <tr className='tr-table' key={`key${index}tr`}>
                                        <td className='td-table' key={`keyindex`}>
                                            {index + 1}
                                        </td>
                                        {Object.entries(valor).map(entry => {
                                            const [key, value] = entry
                                            if (key === 'date_created') return (<td className='td-table' id={`ddd_results_date_created${index}`} key={`ddd_results_date_created${index}`}><h6 className='' key={`h4ddd_results_date_created${index}`} id={`h4ddd_results_date_createde${index}`}>{value}</h6></td>)
                                            if (key === 'hhh_results_type') return (<td className='td-table' id={`hhh_results_type${index}`} key={`hhh_results_type${index}`}><h6 className='' key={`h4hhh_results_type${index}`} id={`h4hhh_results_type${index}`}>{value}</h6></td>)
                                            if (key === 'eee_results_detail_available_quantity') return (<td className='td-table' id={`eee_results_detail_available_quantity${index}`} key={`eee_results_detail_available_quantity${index}`}><h6 className='' key={`h4eee_results_detail_available_quantity${value}`} id={`h4eee_results_detail_available_quantity${value}`}>{value}</h6></td>)
                                            if (key === 'fff_results_result_total') return (<td className='td-table' id={`fff_results_result_total${index}`} key={`resulfff_results_result_totalts_result_total${index}`}><h6 className='' key={`h4fff_results_result_total${index}`} id={`h4fff_results_result_total${index}`}>{value}</h6></td>)
                                            if (key === 'ggg_results_external_references_value') return (<td className='td-table' id={`ggg_results_external_references_value${index}`} key={`ggg_results_external_references_value${index}`}><h6 className='' key={`h4ggg_results_external_references_valuel${index}`} id={`h4ggg_results_external_references_value${index}`}>{value}</h6></td>)
                                        })}</tr>)
                            })}
                        </tbody>
                    </table >
                </section >
                :
                <Loader />
            }
        </>
    )
}

export default TablaDatosAnalisisOp