import React, { useState } from 'react'
import axios from '../../../api/axios';
import TablaDatosMlc from '../reports-components/TablaDatosMlc'
import Loader from '../../Loader'
// import Pagination from '../reports-components/PaginationReport';


const SelectUsers = ({ listUsers, setOpenModal, setRowD, setSku }) => {
    const SINGLE_MKPL = '/api/users/singleMkpl';

    const [refresh, setRefresh] = useState('');
    const [mlc, setMlc] = useState('');
    const [searchTerm, setSearchTerm] = useState('');
    const [sellerItem, setSellerItem] = useState('');
    const [isSellerSelected, setIsSellerSelected] = useState(false);
    const [isMLCSelected, setIsMLCSelected] = useState(false);
    const [isSearchCharged, setIsSearchCharged] = useState(false);
    const [mlcSearched, setMlcSearched] = useState([]);
    const [listOfMlc, setListOfMlc] = useState({});

    const fetchSingleMkpl = async () => {
        try {
            setIsSearchCharged(true);
            const rt = await axios.post(SINGLE_MKPL,
                JSON.stringify({ refresh, mlc }),
                { headers: { 'Content-Type': 'application/json' }, }
            ).then(async res => res).catch(err => console.log(err));
            setListOfMlc(rt['data']);
            setIsSearchCharged(false);
        } catch (error) { console.log(`error 2`, error); }
    }

    const returnText = (mlc) => {
        const text = mlc
            .replace(/ /g, "")
            .replace(/;/g, "")
            .replace(/:/g, "")
            .replace(/,/g, "")
            .replace(/\./g, "")
            .replace(/\\/g, "")
            .replace(/'/g, "")
            .replace(/"/g, "")
            .replace(/a/g, "")
            .replace(/b/g, "")
            .replace(/c/g, "")
            .replace(/d/g, "")
            .replace(/e/g, "")
            .replace(/f/g, "")
            .replace(/g/g, "")
            .replace(/h/g, "")
            .replace(/i/g, "")
            .replace(/j/g, "")
            .replace(/k/g, "")
            .replace(/l/g, "")
            .replace(/m/g, "")
            .replace(/n/g, "")
            .replace(/o/g, "")
            .replace(/p/g, "")
            .replace(/q/g, "")
            .replace(/r/g, "")
            .replace(/s/g, "")
            .replace(/t/g, "")
            .replace(/u/g, "")
            .replace(/v/g, "")
            .replace(/w/g, "")
            .replace(/x/g, "")
            .replace(/y/g, "")
            .replace(/z/g, "")
        const arrText = text.trim().split('M')
        const arrText_ = []
        arrText.forEach((el, index) => index !== 0 ? arrText_.push(`M${el}`.trim()) : '');
        return [...new Set(arrText_)];
    }

    return (
        <div className='selectUserwrapper'>
            <center>
                <h2 className='seller-select'>{sellerItem}</h2>
                <h3 className='seller-select'>{mlcSearched}</h3>
            </center>
            <div className='selectWrapper'>
                {
                    !isSellerSelected ?
                        <table>
                            <thead>
                                <tr key={`input-key-tr`}>
                                    <th key={`input-key-th`}>
                                        <input
                                            key={`input-key`}
                                            autoFocus
                                            type="text"
                                            placeholder='search...'
                                            onChange={(e) => { setSearchTerm(e.target.value); }}
                                        />
                                    </th>
                                </tr>
                            </thead>
                            <tbody>
                                {
                                    listUsers
                                        .filter((val) => {
                                            if (searchTerm === '') { return val; }
                                            else if (val.nickname.toLowerCase().startsWith(searchTerm.toLowerCase())) { return val; }
                                            else { return ''; }
                                        })
                                        .sort((a, b) => a['nickname'] > b['nickname'])
                                        .map((value, index) => {
                                            return (<>
                                                <tr key={`${index}seller`}>
                                                    <td
                                                        key={`input-key-td-${index}`}
                                                        onClick={(e) => {
                                                            setRefresh(value['refresh_token'])
                                                            setIsSellerSelected(true);
                                                            setSellerItem(value['nickname'])
                                                        }}><center key={`input-key-center`} className='items-sellers'>{value['nickname']} / {value['id_seller']} </center></td>
                                                </tr>
                                            </>)
                                        })
                                }
                            </tbody>
                        </table>
                        :

                        !isMLCSelected ?
                            <div>
                                <center>
                                    <textarea
                                        name="mlc-text-area"
                                        className="mlc-text-area" cols="30" rows="10"
                                        placeholder='Insert MLC here...'
                                        onChange={e => { setMlc(e.target.value.trim()); }}
                                    ></textarea>
                                </center>
                                <center>
                                    <button className='btn btn-alert' type='button' onClick={() => {
                                        setIsSellerSelected(false);
                                    }}>Select another seller</button>
                                    <button className='btn btn-success' type='button' onClick={() => {
                                        fetchSingleMkpl();
                                        setMlcSearched(returnText(mlc));
                                        setIsMLCSelected(true);
                                    }

                                    }>Search</button>
                                </center>
                            </div>
                            :
                            <button onClick={() => {
                                setIsMLCSelected(false);
                                setIsSellerSelected(false);
                                setMlcSearched([]);
                                setSellerItem('');
                                setListOfMlc({});
                                setIsSearchCharged(false);
                            }}>New search</button>
                }

            </div>
            {
                isSearchCharged ?
                    <Loader />
                    : isMLCSelected ?
                        <div>
                            {listOfMlc ?
                                <div>
                                    {listOfMlc.items ?
                                        <div>
                                            {
                                                listOfMlc.items.length > 0 ?
                                                    <TablaDatosMlc
                                                        listOfMlc={listOfMlc}
                                                        setOpenModal={setOpenModal}
                                                        setRowD={setRowD}
                                                        rToken={refresh}
                                                        setSku={setSku}
                                                    />
                                                    :
                                                    ''
                                            }
                                        </div>
                                        : ''}
                                </div>
                                : ''}
                        </div>
                        : ''
            }
        </div >
    )
}

export default SelectUsers