import React, { useState, useContext } from 'react'
// import SellerContext from "../../context/SellerProvider";
import Background from '../Background'
import HeaderAdmin from '../admin-zone/HeaderAdmin'
import TablaDatosAnalisisOp from '../admin-zone/analisis-operaciones/TablaDatosAnalisisOp'
import axios from '../../api/axios';


const AnalisisOper = () => {
    // const { seller } = useContext(SellerContext);

    const [listUsers, setListusers] = useState([]);
    const [isLoader, setIsLoader] = useState(true);
    const USERS_GRANTED_ACTIVE_LIST = '/api/users/getOperacionesItems';

    const getListItems = async () => {
        try {
            const list = await axios.post(USERS_GRANTED_ACTIVE_LIST)
                .then(async res => res)
                .catch(err => console.log('error en axios server', err));
            setListusers(list['data']);
            setIsLoader(false);
        } catch (error) { console.log(`error en el try catch`, error); }
    }

    if (isLoader) getListItems();

    return (
        <>
            <HeaderAdmin />
            <Background />
            <div className=''>
                <div align='center'>
                    {/* <h1>{seller.mkpl_id}</h1>
                    <h1>{seller.inventID}</h1> */}
                </div>
                <hr />
                <div className=''>
                    <TablaDatosAnalisisOp
                        oper={listUsers}
                    />

                </div>
            </div>
        </>
    )
}

export default AnalisisOper